+    [cx + 0.02, headY - 0.02],               // 2: r_eye
+    [cx - 0.04, headY],                       // 3: l_ear
+    [cx + 0.04, headY],                       // 4: r_ear
+    [cx - shoulderW, shoulderY],              // 5: l_shoulder
+    [cx + shoulderW, shoulderY],              // 6: r_shoulder
