+  [1, 3], [2, 4],         // eyes -> ears
+  [5, 7], [7, 9],         // left arm: shoulder-elbow, elbow-wrist
+  [6, 8], [8, 10],        // right arm: shoulder-elbow, elbow-wrist
+  [5, 11], [6, 12],       // torso: shoulder-hip
+  [11, 13], [13, 15],     // left leg: hip-knee, knee-ankle
